diff --git a/internal/base32/base32_test.go b/internal/base32/base32_test.go
new file mode 100644
--- /dev/null
+++ b/internal/base32/base32_test.go
@@
+package base32
+
+import (
+	"bytes"
+	"testing"
+)
+
+func TestRoundTripSmall(t *testing.T) {
+	for _, in := range []string{"", "f", "fo", "foo", "foob", "fooba", "foobar", "hi"} {
+		got, err := Decode(Encode([]byte(in)))
+		if err != nil {
+			t.Fatalf("decode %q: %v", in, err)
+		}
+		if string(got) != in {
+			t.Errorf("round-trip %q -> %q", in, got)
+		}
+	}
+}
+
+func TestRoundTripBinary(t *testing.T) {
+	raw := make([]byte, 256)
+	for i := range raw {
+		raw[i] = byte(i)
+	}
+	got, err := Decode(Encode(raw))
+	if err != nil {
+		t.Fatalf("decode: %v", err)
+	}
+	if !bytes.Equal(got, raw) {
+		t.Errorf("binary round-trip mismatch")
+	}
+}
+
+func TestDecodeKnownVector(t *testing.T) {
+	got, err := Decode(Encode([]byte("foobar")))
+	if err != nil {
+		t.Fatal(err)
+	}
+	if !bytes.Equal(got, []byte("foobar")) {
+		t.Errorf("got %q", got)
+	}
+}
